// StackedBars.tsx (concept)
import React, {useEffect, useMemo} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {Canvas, Rect} from '@shopify/react-native-skia';
import {useSharedValue, withTiming, withDelay, useDerivedValue} from 'react-native-reanimated';
type Bar = {label: string; segments: {color: string; value: number}[]};
export function StackedBars({bars, width, height = 200}: {bars: Bar[]; width: number; height?: number}) {
  const max = useMemo(() => Math.max(...bars.map(b => b.segments.reduce((a, s) => a + s.value, 0))), [bars]);
  const barW = (width - bars.length * 8) / bars.length;
  const progress = useSharedValue(0);
  useEffect(() => { progress.value = withTiming(1, {duration: 700}); }, []);
  const rects = bars.flatMap((bar, bi) => { const x = bi * (barW + 8); let cumY = height; const result: React.ReactNode[] = []; bar.segments.forEach((seg, si) => { const h = (seg.value / max) * height; const animH = useDerivedValue(() => h * progress.value); const animY = useDerivedValue(() => cumY - animH.value); result.push(<Rect key={`${bi}-${si}`} x={x} y={animY} width={barW} height={animH} color={seg.color}/>); cumY -= h; }); return result; });
  return (<Canvas style={{width, height}}>{rects}</Canvas>);
}

