import React, {useState} from 'react';
import {StyleSheet, View, Text} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import {runOnJS} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
const SIZE = 32; const COUNT = 5;
export function StarRating({value, onChange}: {value: number; onChange: (v: number) => void}) {
  const [width, setWidth] = useState(COUNT * SIZE);
  const update = (v: number) => { Haptics.selectionAsync(); onChange(v); };
  const pan = Gesture.Pan().minDistance(0).onUpdate(e => { const stars = Math.max(0, Math.min(COUNT, Math.ceil((e.x / width) * COUNT))); if (stars !== value) runOnJS(update)(stars); });
  const tap = Gesture.Tap().onEnd(e => { const stars = Math.max(1, Math.min(COUNT, Math.ceil((e.x / width) * COUNT))); runOnJS(update)(stars); });
  return (<GestureDetector gesture={Gesture.Race(tap, pan)}><View style={s.row} onLayout={e => setWidth(e.nativeEvent.layout.width)}>{Array.from({length: COUNT}).map((_, i) => (<Text key={i} style={[s.star, i < value && s.starFilled]}>{i < value ? '★' : '☆'}</Text>))}</View></GestureDetector>);
}
