import React, {useMemo} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Rect} from '@shopify/react-native-skia';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import {runOnJS} from 'react-native-reanimated';
const CELL = 12; const GAP = 2;
export function HeatmapCalendar({data, onCellTap}: {data: number[]; onCellTap?: (week: number, day: number, value: number) => void}) {
  const tap = Gesture.Tap().onEnd(e => { const week = Math.floor(e.x / (CELL + GAP)); const day = Math.floor(e.y / (CELL + GAP)); if (onCellTap) runOnJS(onCellTap)(week, day, data[week * 7 + day] ?? 0); });
  const max = useMemo(() => Math.max(...data, 1), [data]);
  const color = (v: number) => { const t = v / max; if (t === 0) return '#1C1C1E'; if (t < 0.25) return '#0A4429'; if (t < 0.5) return '#006D32'; if (t < 0.75) return '#26A641'; return '#39D353'; };
  return (<GestureDetector gesture={tap}><View style={{width: 52 * (CELL + GAP), height: 7 * (CELL + GAP)}}><Canvas style={StyleSheet.absoluteFill}>{Array.from({length: 52 * 7}).map((_, i) => { const week = Math.floor(i / 7); const day = i % 7; return <Rect key={i} x={week * (CELL + GAP)} y={day * (CELL + GAP)} width={CELL} height={CELL} color={color(data[i] ?? 0)}/>; })}</Canvas></View></GestureDetector>);
}

