import {Canvas, Line, vec, Group} from '@shopify/react-native-skia';
import {useSharedValue, useDerivedValue, withSpring, interpolate} from 'react-native-reanimated';
export function HamburgerX({open}: {open: boolean}) {
  const v = useSharedValue(open ? 1 : 0);
  React.useEffect(() => { v.value = withSpring(open ? 1 : 0, {damping: 16, stiffness: 280}); }, [open]);
  const top = useDerivedValue(() => ({p1: vec(4, 8 + interpolate(v.value, [0, 1], [0, 4])), p2: vec(20, 8 + interpolate(v.value, [0, 1], [0, 4]))}));
