  const bot = useDerivedValue(() => ({p1: vec(4, 16 + interpolate(v.value, [0, 1], [0, -4])), p2: vec(20, 16 + interpolate(v.value, [0, 1], [0, -4]))}));
  const rot = useDerivedValue(() => v.value * 45);
  return (<View style={{width:24, height:24}}><Canvas style={StyleSheet.absoluteFill}><Group transform={useDerivedValue(() => [{rotate: rot.value * Math.PI / 180}, {translateX: 12}, {translateY: 12}]) as any}><Line p1={vec(-8, -2)} p2={vec(8, -2)} color='#fff' strokeWidth={2}/><Line p1={vec(-8, 2)} p2={vec(8, 2)} color='#fff' strokeWidth={2}/></Group></Canvas></View>);
